import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import { GithubRepoModel } from '@modules/github/db/github-repos.model';
import { IGithubApiRepo } from '@modules/github/types/github-api.interface';
import { IGithubRepoBase } from '@modules/github/types/github-repo.interface';

const mockRepo: IGithubRepoBase = {
	_id: 'repo-uuid-1',
	installation_id: 'install-uuid-1',
	github_repo_id: 111222333,
	name: 'api',
	full_name: 'acme-corp/api',
	private: true,
	default_branch: 'main',
	synced_at: null,
	created_at: new Date('2026-04-14'),
	updated_at: new Date('2026-04-14'),
};

const mockKnexRead = {
	where: jest.fn().mockReturnThis(),
	select: jest.fn(),
};
const mockKnexWrite = {
	insert: jest.fn().mockReturnThis(),
	where: jest.fn().mockReturnThis(),
	whereIn: jest.fn().mockReturnThis(),
	delete: jest.fn(),
	onConflict: jest.fn().mockReturnThis(),
	merge: jest.fn(),
};

const knexReadFn = jest.fn().mockReturnValue(mockKnexRead);
const knexWriteFn = jest.fn().mockReturnValue(mockKnexWrite);

(knexWriteFn as jest.Mock & { fn: { now: jest.Mock } }).fn = {
	now: jest.fn().mockReturnValue('NOW()'),
};

describe('GithubRepoModel', () => {
	let model: GithubRepoModel;

	beforeEach(async () => {
		jest.clearAllMocks();

		knexReadFn.mockReturnValue(mockKnexRead);
		knexWriteFn.mockReturnValue(mockKnexWrite);
		mockKnexRead.where.mockReturnThis();
		mockKnexWrite.insert.mockReturnThis();
		mockKnexWrite.where.mockReturnThis();
		mockKnexWrite.whereIn.mockReturnThis();
		mockKnexWrite.onConflict.mockReturnThis();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				GithubRepoModel,
				{ provide: KNEX_READ_CONNECTION, useValue: knexReadFn },
				{ provide: KNEX_WRITE_CONNECTION, useValue: knexWriteFn },
			],
		}).compile();

		model = module.get<GithubRepoModel>(GithubRepoModel);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(model).toBeDefined();
	});

	describe('upsertMany', () => {
		it('should do nothing when repos array is empty', async () => {
			await model.upsertMany({ installationId: 'install-uuid-1', repos: [] });
			expect(knexWriteFn).not.toHaveBeenCalled();
		});

		it('should insert repos with onConflict merge', async () => {
			mockKnexWrite.merge = jest.fn().mockResolvedValue(undefined);
			const repos: IGithubApiRepo[] = [
				{
					id: mockRepo.github_repo_id,
					name: mockRepo.name,
					full_name: mockRepo.full_name,
					private: mockRepo.private,
					default_branch: mockRepo.default_branch,
				},
			];

			await model.upsertMany({ installationId: 'install-uuid-1', repos });

			expect(knexWriteFn).toHaveBeenCalled();
			expect(mockKnexWrite.onConflict).toHaveBeenCalledWith('github_repo_id');
			expect(mockKnexWrite.merge).toHaveBeenCalled();
		});

		it('should throw when DB throws', async () => {
			mockKnexWrite.merge = jest.fn().mockRejectedValue(new Error('DB error'));
			const repos: IGithubApiRepo[] = [
				{
					id: mockRepo.github_repo_id,
					name: mockRepo.name,
					full_name: mockRepo.full_name,
					private: mockRepo.private,
					default_branch: mockRepo.default_branch,
				},
			];

			await expect(model.upsertMany({ installationId: 'install-uuid-1', repos })).rejects.toThrow(
				'DB error',
			);
		});
	});

	describe('findByInstallationId', () => {
		it('should return repos for the installation', async () => {
			mockKnexRead.select = jest.fn().mockResolvedValue([mockRepo]);

			const result = await model.findByInstallationId({ installationId: mockRepo.installation_id });

			expect(result).toEqual([mockRepo]);
		});

		it('should throw when DB throws', async () => {
			mockKnexRead.select = jest.fn().mockRejectedValue(new Error('DB read error'));

			await expect(
				model.findByInstallationId({ installationId: mockRepo.installation_id }),
			).rejects.toThrow('DB read error');
		});
	});

	describe('removeByGithubIds', () => {
		it('should do nothing when githubRepoIds is empty', async () => {
			await model.removeByGithubIds({
				installationId: mockRepo.installation_id,
				githubRepoIds: [],
			});
			expect(knexWriteFn).not.toHaveBeenCalled();
		});

		it('should delete repos with matching github ids', async () => {
			mockKnexWrite.delete = jest.fn().mockResolvedValue(1);

			await model.removeByGithubIds({
				installationId: mockRepo.installation_id,
				githubRepoIds: [mockRepo.github_repo_id],
			});

			expect(mockKnexWrite.whereIn).toHaveBeenCalledWith('github_repo_id', [
				mockRepo.github_repo_id,
			]);
			expect(mockKnexWrite.delete).toHaveBeenCalled();
		});

		it('should throw when DB throws', async () => {
			mockKnexWrite.delete = jest.fn().mockRejectedValue(new Error('DB delete error'));

			await expect(
				model.removeByGithubIds({
					installationId: mockRepo.installation_id,
					githubRepoIds: [mockRepo.github_repo_id],
				}),
			).rejects.toThrow('DB delete error');
		});
	});
